 //            + JN free(536,534,539,538,551,552,537)
 //            -an modificat(103,105)
 //
 //3.subB/initialize-->
 //            -accize free + JN free(536,534,539,538,551,552,537)
 //            -an modificat(103,105)
 //
 //4.pune_sume(bloc)-->suma dedu.,suma de restit.
 //            -accize + JN(504) + medic.(450,455,456) + imp.specific(117,116)
 //
 //5.corecteaza_scad_cbug(bloc,oblig1,scad1,cbug1)-->
 //            -accize free + JN free(536,534,539,538,551,552,537) 
 //6.Button3 (instr.)
