 //----------------------------------------


 //alege obligatie
 //respinge oblig.trimestriale (102,106,111,121,450,455,456,755,756,758) in luni diferite de 3,6,9,12
 //respinge oblig.semestriale (130) in luni diferite de 6,12 (si 07/2017)
 //preia COD_BUGETAR,model,pune SCADENTA initiala
 //pentru 105    apare Scad_JN_AC
 //pentru accize(211..259) si JN(536,534,539,538,551,552,537) apare B_SCAD

 //anuleaza sume
 SUMA01I.rawValue=0;
