var v0; 
var v2;

//---------------

//------------------          
if (form1.sub1.an_r.rawValue!=null && form1.sub1.luna_r.rawValue!=null ) 
{//bloc
  //alege obligatie
  var v1 = COD_IMP;
  popUp.tipOBLIG(v1);

       //Scad_JN_AC visible/invisible
       Scad_JN_AC.presence="invisible" ;

       v0=COD_IMP.rawValue;
       if (v0!=null)
       {//2
        v1=v0.substr(0,3);
        v2=v0.substr(0,4);
        //an modificat
        //----------------

        //var v0=0;
        var trim1=form1.sub1.luna_r.rawValue;
        var v_er=0;

        //103,105 exceptie: scadenta cu luna+6 pt (luna_r,an_r) in [12/2021,11/2022 ]

        //--------------------

        //if (form1.sub1.an_r.rawValue>=2021  && (v1==130 || v1==121))
        /*
        if(form1.sub1.d_modif.rawValue==1 && v1!=103)
        {
            app.alert("Ati bifat ' Ultimul TRIM. dinainte de primul an fiscal modificat' si nu ati selectat oblig.103 !");
            COD_IMP.rawValue=null;
            v_er=1;
         }                
       */ 

        if (form1.sub1.an_r.rawValue==2021 && trim1!=12) 
        {
          if (form1.sub1.tipD.D100.rawValue==1 ) 
          {
            app.alert("Obligatiile se raporteaza in D100 incepand cu luna 12/2021 !");
            COD_IMP.rawValue=null;
            v_er=1;
          }
          //---
          if (form1.sub1.tipD.D710.rawValue==2 && !(v1==130 || v1==121)) 
          {
            app.alert("Obligatiile diferite de (121,130) se raporteaza in D710 incepand cu luna 12/2021 !");
            COD_IMP.rawValue=null;
            v_er=1;
          }   

        }
        //-------121 3%-----
         if (form1.sub1.an_r.rawValue>2025 && v0=="121--Impozit pe ven. microintreprinderilor cota 3% ")       
          {
            app.alert("Obligatia '121--Impozit pe ven. microintreprinderilor cota 3%' nu se raporteaza pentru an > 2025 !");
            COD_IMP.rawValue=null;
            v_er=1;
          } 
     //---------------

        //-------------
        //anuale (706) doar in luna 12          
        if (v1==706 && form1.sub1.d_dizolv.rawValue==0 && (trim1!=12 || form1.sub1.an_r.rawValue<2024))
        {  app.alert("Oblig.'706' este obligatie anuala si se declara in luna 12 (incepand cu anul 2024) !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }

        //semestriale (130) doar in lunile 6,12          
        if (  (v1==130) &&   form1.sub1.d_dizolv.rawValue==0 &&   !(trim1==6 || trim1==12 )   )
        {  app.alert("Obligatiile semestriale se declara in lunile 6,12 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }

        //trimestriale (102,121,450,455,456,755,756,758,   107,127scutite) doar in lunile 3,6,9,12        
        if (  ((v1==102 ||  v1==121  || v1==450 ||  v1==455 || v1==456 || v1==755 || v1==756 || 
                v1==758  || v1==107 || v1==127 || v1==763 || v1==108  || v1==707) && form1.sub1.d_dizolv.rawValue==0) && 
            !(trim1==3 || trim1==6 || trim1==9 || trim1==12))            
        {  app.alert("Obligatiile trimestriale se declara in lunile 3,6,9,12 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }
        //trim1=luna_r
        //trimestriale (117 i.credit) doar in lunile 3,6,9,12 pt.d_dizolv=0       
        if ( v1==117 && form1.sub1.d_dizolv.rawValue==0 && !(trim1==3 || trim1==6 || trim1==9 || trim1==12))            
        {  app.alert("Obligatiile trimestriale se declara in lunile 3,6,9,12 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }
        if ( v1==117 && form1.sub1.d_dizolv.rawValue==0 && trim1==12)  form1.sub1.d_trim.rawValue=1;       

     //------------------------------  
        //7542 doar in lunile 1,2,3
        if (v2==7542 && trim1>3 )
        {  app.alert("Oblig.'7542--Compensatii (anii urmatori) aferente dreptului de trecere in schimbul limitarilor aduse dreptului de folosinta' se declara doar in lunile 1,2 sau 3 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }

        if (v1==626 &&  form1.sub1.an_r.rawValue<2021)
        {  app.alert("Oblig.'626--Plati anticipate ale impozitului pentru unele venituri din activitati independente ' se declara incepand cu 01/2021 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }
        if (v1==607 &&  form1.sub1.an_r.rawValue>2021)
        {  app.alert("Atentie ! Oblig.'607--Impozit pe ven. din pensii' nu se mai se declara incepand cu 01/2022 !");
           //COD_IMP.rawValue=null;
           //v_er=1;
           //break;
        }
        //  
        //if (v1==708 &&  (form1.sub1.tipD.rawValue==1 || (form1.sub1.an_r.rawValue==2022 && form1.sub1.luna_r.rawValue<9)))
        if (v1==708 &&  (form1.sub1.an_r.rawValue<2022 || (form1.sub1.an_r.rawValue==2022 && form1.sub1.luna_r.rawValue<9)))        
        {  app.alert("Oblig.'708--Contributie la Fondul de Tranzitie Energetica' se declara incepand cu 09/2022 !");
           COD_IMP.rawValue=null;
           v_er=1;
           //break;
        }              
        //----------------
        //161 doar in per.  11.2021-03.2022 -03.2023
        var v0=0;
