function deblochez(){
//deblochez
var field;
	var v1=xfa.host.numPages;

	for (var nPageCount = 0; nPageCount < xfa.host.numPages; nPageCount++) {
		var oFields = xfa.layout.pageContent(nPageCount, "field");
		var nNodesLength = oFields.length;
		//
		for (var nNodeCount = 0; nNodeCount < nNodesLength; nNodeCount++) {
		    field = oFields.item(nNodeCount);
		    if (field.assist.toolTip.value == "Calcul" ) field.access="readOnly";
		    else field.access = "open";

		}
    }
//blochez semnatura
  form1.sub2.B_PRINT.access="readOnly";   //blochez listare
  form1.sub2.SignatureField1.access="readOnly";


  monitor1.removeDataObjects();               //sterg fisier atasat

}//deblochez




function removeDataObjects(){
	file = event.target;
	var d = file.dataObjects;
	if (d != null){
		for (var i = 0; i < d.length; i++){
			file.removeDataObject(d[i].name);
		}
	}
}

