  var ob1;
  var cbu1;            
  var mod1;
        for(var i=1;i<nr1;i++)
        {
        	cLine=vec2[i];
        	i1=0;
            //-----------COD_IMP-----------
            j1=cLine.indexOf(",",i1);
            ob1=cLine.substr(i1,j1-i1);
            i1=j1+1;

            //-----------COD_BUGETAR-----------
            j1=cLine.indexOf(",",i1);
