            i1=j1+1;
            //-----------MODEL-----------
            lung1=cLine.length; //ultimul camp
	        mod1=cLine.substr(i1,lung1-i1); 

            if (oblig==ob1) return cLine;
         }
  return cLine; 
}//prel2




function pune_scad_initiala(mod1){
