//LUNAR_105  -->105 
//LUNAR_25LLU  -->103 

//AN_780      -->780,781
//FREE        -->accize 
//TRIM_25U2   -->450,455,456
//TRIM_25U4   -->455 din 09.2018
//AN_754      -->7542
//15LUNI / 18LUNI -->131,132

      var scad2 = new Date();

      //var refMonth = scad1.getMonth();
      var refMonth =  form1.sub1.luna_r.rawValue-1;
      var refMonth2 = (refMonth<9) ? "0" + (refMonth+1) : (refMonth+1);

      //var refYear = scad1.getFullYear();
      var refYear = form1.sub1.an_r.rawValue;
      var refYear2 = (""+refYear).substr(2);

      var endMonth = "";
      var endYear = "";

      //=====================================
      if (mod1=="LUNAR_25U") 
      {
        endYear = (refMonth < 11) ? refYear : refYear+1; // 11=december: skip to next year, january
        endMonth = (refMonth < 11) ? refMonth+1 : 0;     // 11=december: skip to next year, january
        scad2 = new Date(endYear, endMonth, 25,12,0,0);        
      }//LUNAR_25LU  

       if (mod1=="ANC_714")
      {//714  scadenta 3003AC
              scad2 = new Date(refYear, 2, 30,12,0,0);}       
       if (mod1=="ANC_715")
      {//715  scadenta 3003AC
              scad2 = new Date(refYear, 2, 30,12,0,0);}    
       if (mod1=="ANC_716")
      {//716  scadenta 3003AC
              scad2 = new Date(refYear, 2, 30,12,0,0);}    
       if (mod1=="ANC_717")
      {//717  scadenta 3103AC
              scad2 = new Date(refYear, 2, 31,12,0,0);}    
       if (mod1=="ANC_718")
      {//718  scadenta 3103AC
              scad2 = new Date(refYear, 2, 31,12,0,0);}                                                    
       if (mod1=="ANC_719")
      {//719  scadenta 3003AC
              scad2 = new Date(refYear, 2, 30,12,0,0);}  

      //==================115================
