          else endMonth=refMonth+3;

          if (endMonth>11) endMonth=endMonth-12;
          endYear=refYear+1;                   
        }//dizolv=0
        //
        if (form1.sub1.d_dizolv.rawValue==1)
        {
          endMonth = refMonth+1;
          endYear=refYear;
          if (endMonth>11) 
          {
            endMonth=endMonth-12;          
            endYear=refYear+1;
          }
        }//dizolv=1

           scad2 = new Date(endYear, endMonth, 25,12,0,0)  //25LU        
      }//AN_115 

      //==================125==========================
      if (mod1=="AN_125") 
      {
        endYear = (refMonth < 11) ? refYear : refYear+1; // 11=december: skip to next year, january
        endMonth = (refMonth < 11) ? refMonth+1 : 0;     // 11=december: skip to next year, january
        scad2 = new Date(endYear, endMonth, 25,12,0,0);  

        //exceptii 2021-2025 cu scadenta 250622 pt.12/2021

        if (form1.sub1.d_dizolv.rawValue==0)
        {         
          if ((refYear>=2021 && refYear<=2025 )&& refMonth==11) 
