           if (refYear==2021 && refMonth==11)  scad2 = new Date(2022, 5, 25,12,0,0); // exceptie 25.06.2022 pentru 12/2021
           if (refYear==2022 && refMonth==11)  scad2 = new Date(2023, 5, 25,12,0,0); 
