      //==================102=====================
       // 102 cu 3 scadente 25LU si 2512 pt.luna=12 si (250622 pt.12/2021)
      if (mod1=="LUNAR_102")
      {//scadenta 2512AC
           if (form1.sub1.d_dizolv.rawValue==1)
           {
            endMonth = (refMonth < 11) ? refMonth+1 : refMonth+1;
