       {
        if (form1.sub1.d_dizolv.rawValue==0)
        { 
            if (form1.sub1.d_trim.rawValue==1)
            {
               if (refYear>=2021) endMonth=refMonth+6; //25L6
               //if (refYear>=2021 && refYear<=2025) endMonth=refMonth+6; //25L6               
               //else endMonth=refMonth+3; //25L3              
            }
            else  endMonth =  refMonth+1; //25LU
            endYear = refYear;             
        }//dizolv=0
        else
        {
          endMonth = refMonth+1;  //25LU
          endYear=refYear;
        }//dizolv=1
        //-------------------
          if (endMonth>11) 
          {
            endMonth=endMonth-12;          
            endYear=refYear+1;
          }            
          scad2 = new Date(endYear, endMonth, 25,12,0,0)  //25LU          

       }//LUNAR_116     

       //----------------------------

       if (mod1=="LUNAR_117") 
       {
        if (form1.sub1.d_dizolv.rawValue==0)
        { 
