        if (refYear==2021 && refMonth==5)   scad2 = new Date(2021, 11, 25,12,0,0); // exceptie 25.12.2021 pentru 06/2021
        if (refYear==2022 && refMonth==5)   scad2 = new Date(2022, 6, 25,12,0,0);  // exceptie 25.07.2022 pentru 06/2022

        //----------------
        if (form1.sub1.d_dizolv.rawValue==0)
