function pune_nrev(bloc){
  var scad11;
  var oblig1;

       v1=bloc.COD_IMP.rawValue;
       if (v1!=null) 
       {
        oblig1=v1.substr(0,3);
        scad11=bloc.SCADENTA.rawValue;
       }

    var nrev1 = null;
    var cifControl = 0;

if (v1!=null && scad11!=null)
{     
    //--------------------
    if (scad11.indexOf(".")>-1)
    {       
      var dateParts = scad11.split(".");
      var zYear = new Number(dateParts[2]);
      var zMonth = new Number(dateParts[1]) - 1;
      var zDay = new Number(dateParts[0]);
    }
    if (scad11.indexOf("/")>-1)
    {       
      var dateParts = scad11.split("/");
      var zYear = new Number(dateParts[2]);
      var zMonth = new Number(dateParts[1]) - 1;
      var zDay = new Number(dateParts[0]);
    }

    if (scad11.indexOf("-")>-1)
    {
      var dateParts = scad11.split("-");
      var zYear = new Number(dateParts[0]);
      var zMonth = new Number(dateParts[1]) - 1;
      var zDay = new Number(dateParts[2]);
    }
      var scad1 = new Date(zYear, zMonth, zDay,12,0,0);    
    //--------------------

      var refMonth =  form1.sub1.luna_r.rawValue-1;
      var refMonth2 = (refMonth<9) ? "0" + (refMonth+1) : (refMonth+1);
      var refYear = form1.sub1.an_r.rawValue;
      var refYear2 = (""+refYear).substr(2);

      var scad2 = "";
      scad2 += (scad1.getDate()<10) ? "0"+scad1.getDate() : scad1.getDate();
      scad2 += ((scad1.getMonth()+1)<10) ? "0"+(scad1.getMonth()+1) : (scad1.getMonth()+1)
      scad2 += (""+scad1.getFullYear()).substr((((""+scad1.getFullYear()).length)-2));

      //------------------------------
      nrev1 = "10" + oblig1 + "01" + refMonth2 + refYear2 + scad2 + "0" + "000";
      for (i=0; i < nrev1.length; i++){
           cifControl = (cifControl + new Number (nrev1[i]));
      }
      cifControl = ("" + cifControl).substr((cifControl.length)-2);// string with the 2 rightmost chars of cifControl
      nrev1 += ("" + cifControl);
      //------------------------------
}//v1!=null && scad11!=null

return nrev1;

}//pune_nrev



function calc_TOT(){
  var TOT0=0;
  var TOT1=0;
  var TOT2=0;
  var TOT3=0; 
  var bl1;
  var nrk1 = form1.subB.all.length;
if (form1.sub1.tipD.D100.rawValue==1) 
{  
  for (var k1=0;k1<nrk1;k1++)
  {
    bl1=form1.subB.all.item(k1);
    if (bl1.COD_BUGETAR.rawValue=="XXXXXXXXXX") TOT0=TOT0+bl1.SUMA01I.rawValue;
    if (bl1.COD_BUGETAR.rawValue=="5503XXXXXX") TOT1=TOT1+bl1.SUMA03I.rawValue;
    if (!(bl1.COD_BUGETAR.rawValue=="XXXXXXXXXX" || bl1.COD_BUGETAR.rawValue=="5503XXXXXX"))  TOT2=TOT2+bl1.SUMA03I.rawValue;

    TOT3=TOT3+bl1.SUMA01I.rawValue+bl1.SUMA02I.rawValue+bl1.SUMA03I.rawValue+bl1.SUMA04I.rawValue;
    TOT3=TOT3+bl1.SUMA05I.rawValue+bl1.SUMA06I.rawValue+bl1.SUMA07I.rawValue;   //din 12.2020              
  }
}
if (form1.sub1.tipD.D710.rawValue==2) 
{  
  for (var k1=0;k1<nrk1;k1++)
  {
    bl1=form1.subB.all.item(k1);
    if (bl1.COD_BUGETAR.rawValue=="XXXXXXXXXX") TOT0=TOT0+bl1.SUMA01C.rawValue;
    if (bl1.COD_BUGETAR.rawValue=="5503XXXXXX") TOT1=TOT1+bl1.SUMA03C.rawValue;
    if (!(bl1.COD_BUGETAR.rawValue=="XXXXXXXXXX" || bl1.COD_BUGETAR.rawValue=="5503XXXXXX"))  TOT2=TOT2+bl1.SUMA03C.rawValue;

    TOT3=TOT3+bl1.SUMA01I.rawValue+bl1.SUMA02I.rawValue+bl1.SUMA03I.rawValue+bl1.SUMA04I.rawValue+
              bl1.SUMA01C.rawValue+bl1.SUMA02C.rawValue+bl1.SUMA03C.rawValue+bl1.SUMA04C.rawValue;
    TOT3=TOT3+bl1.SUMA05I.rawValue+bl1.SUMA06I.rawValue+bl1.SUMA07I.rawValue;   //din 12.2020  
    TOT3=TOT3+bl1.SUMA05C.rawValue+bl1.SUMA06C.rawValue+bl1.SUMA07C.rawValue;   //din 12.2020                     
  }
}


form1.SUMA0.rawValue=TOT0; 
form1.SUMA1.rawValue=TOT1;
form1.SUMA2.rawValue=TOT2;
form1.subA.totalPlata_A.rawValue=TOT3;  
}//calc_TOT()





