function corecteaza_scad_cbug(bloc,oblig1,scad1,cbug1){
//corecteaza la validare scad,cbug daca oblig1 e corecta
var v1=oblig1.substr(0,3);
var v2=oblig1.substr(0,4);
var er1=0;
//var bloc=form1.subB.all.item(nrbloc);            
var cLine;         

//------cbu1,scad_initiala---
//if (v1==455 || v1==754 ||  v1==763) cLine=monitor2.prel2(v2);  ////////
//if (v1==455 || v1==754 || v1==717 || v1==132 || v2==7011) cLine=monitor2.prel2(v2);  ////////
if (v1==455 || v1==754 || v1==717 || v1==132 || v1==701) cLine=monitor2.prel2(v2);  ////////
else cLine=monitor2.prel2(v1);

if (cLine==null) {er1=1; return er1;}

           var i1=0;
           var j1;
           var lung1;
           var ob1;
           var cbu1;            
           var mod1;
           var scad_initiala;
           var nrev1;                   
            //-----------COD_IMP-----------
            j1=cLine.indexOf(",",i1);
            //ob1=cLine.substr(i1,j1-i1);
            i1=j1+1;
            //-----------COD_BUGETAR-----------
            j1=cLine.indexOf(",",i1);
            cbu1=cLine.substr(i1,j1-i1);


            if (cbug1!=cbu1) {bloc.COD_BUGETAR.rawValue=cbu1; er1=2; }//corecteaza COD_BUGETAR
            i1=j1+1;

            //-----------MODEL-----------
            lung1=cLine.length; //ultimul camp
	        mod1=cLine.substr(i1,lung1-i1);



            scad_initiala=monitor2.pune_scad_initiala(mod1); /////////
            //nrev1=monitor2.pune_nrev(bloc); //pus la calculate

//--------------------------------------                       

//pentru JN (536,534,539,538,537) scadenta FREE neconditionat
//pentru JN (551,552) scadenta FREE neconditionat din 06.2022

//pentru accize       scadenta FREE trebuie sa fie 25LU sau sa se incadreze in (luna,an) de raportare
var refMonth =  form1.sub1.luna_r.rawValue; 
var refYear  =  form1.sub1.an_r.rawValue;

      var v_accize = 0;

      if (cauta_accize(v1)) v_accize = 1;
      //if (v1==536 || v1==537 || v1==539 || v1==538) v_accize = 1;

      if (scad1!=null && scad_initiala!=null && scad1!=scad_initiala && 
          !(v1==536 || v1==534 || v1==539 || v1==538 || v2==4552 || v1==551 || v1==552  || v1==553 || v1==537 ))  //701
      {
         if (v_accize ==0) { bloc.SCADENTA.rawValue=scad_initiala;  bloc.SCADENTA2.rawValue=scad_initiala; er1=3; } //corectie SCADENTA // && v1!=701
         if (v_accize ==1 )
         {//verific la accize scadenta!=25LU sa se incadreze in (luna,an) de raportare   
             if (scad1.indexOf("/")>-1) {var dateParts = scad1.split("/"); var zYear = new Number(dateParts[2]);}
             if (scad1.indexOf(".")>-1) {var dateParts = scad1.split("."); var zYear = new Number(dateParts[2]);}
             if (scad1.indexOf("-")>-1) {var dateParts = scad1.split("-"); var zYear = new Number(dateParts[0]);}
             var zMonth = new Number(dateParts[1]);

             if (refMonth!=zMonth || refYear!=zYear) {bloc.SCADENTA.rawValue=scad_initiala;  bloc.SCADENTA2.rawValue=scad_initiala; er1=3; } //corectie SCADENTA
         }
      }
//0-corect,1-oblig,2-cbug,3-scad  
//app.alert(bloc.SCADENTA.rawValue);
return er1;
}//corecteaza_scad_cbug(bloc,oblig1,scad1,cbug1)




function cauta_accize(v1)
{
var v_acc = false;
if (v1==null) return v_acc;
//247 din 01.2026
if (v1==211 || v1==216 || v1==212 || v1==217 || v1==213 || v1==214 || v1==215 || v1==221 ||
       v1==222 || v1==224 || v1==225 || v1==231 || v1==232 || v1==233 || v1==234 || v1==235 ||
       v1==236 || v1==238 || v1==237 || v1==270 || v1==226 || v1==227  || v1==228 || v1==245 || v1==246 || v1==229 || v1==247) v_acc = true;
return v_acc;       
}

