function valid_trim()
{
var sir_err="";
//obligatie
var nrk1 = form1.subB.all.length;
for (var k1=0;k1<nrk1;k1++)
{//for obligatie
  var bl1=form1.subB.all.item(k1);
  var v0=bl1.COD_IMP.rawValue;
  if (v0!=null)
  {
        var v1=v0.substr(0,3);
        var trim1=form1.sub1.luna_r.rawValue;
        if (  ((v1==102 ||  v1==121 || v1==450 ||  v1==455 || v1==456 || v1==755 || v1==756 || v1==758) && form1.sub1.d_dizolv.rawValue==0) && 
            !(trim1==3 || trim1==6 || trim1==9 || trim1==12))
        {
           sir_err=sir_err  + "\r\n" + "Obligatie trimestriala (" + v1 + ") la nr.crt."+ (k1+1) + ", ce se declara doar in lunile 3,6,9 si 12 (daca PJ nu e in dizolvare), ";           
        }

        if ( v1==125 && form1.sub1.d_dizolv.rawValue==0 &&  trim1!=12)
        {
           sir_err=sir_err  + "\r\n" + "Obligatia (" + v1 + ") la nr.crt."+ (k1+1) + ", se declara doar in luna 12 (daca PJ nu e in dizolvare), ";           
        }        

        //semestriale (130) doar in lunile 6,12          
        if (  (v1==130) &&   form1.sub1.d_dizolv.rawValue==0 &&   !(trim1==6 || trim1==12 || (trim1==7 && form1.sub1.an_r.rawValue==2017))   )
        {  
          sir_err=sir_err  + "\r\n" + "Obligatie semestriala (" + v1 + ") la nr.crt."+ (k1+1) + ", ce se declara doar in lunile 6 si 12 (daca PJ nu e in dizolvare), ";                   
        }              
  }      
}//for obligatie   
if (sir_err!="") app.alert(sir_err);

}//valid_trim





