function unicit_oblig(){
//cu return mesaj de eroare 
//in validari
//unicitate: COD_IMP+scadenta-->NR_JUSTIFICATIV

  var v2 = new Array();
  var errMess1 = "";

  var sir = "";
  var nr2;
  //var er1=0;
  var compare_a;
  var compare_b;

  var v3;   //nu intra in unicitate pt.ca au NR_JUSTIFICATIV diferit, dar ar trebui
  var v_754=0; //7541 si 7542
  var v_717=0; //7171 si 7172

  var v_455=0; //4551 si 4552
  var v_701=0; //7011 si 7012 si 7013
  var v_132=0; //1321 si 1322

  //umple v2
    nr2 = form1.subB.all.length;    
    for (var j=0; j<nr2; j++){
      sir  = form1.subB.all.item(j).NR_JUSTIFICATIV.rawValue;
      //------------
      v3=sir.substr(2,3); //16.09.2016 exceptie unicitate pe COD_IMP

      if (v3==754) v_754+=1; //7541 si 7542
      if (v3==717) v_717+=1; //7171 si 7172
      //
      if (v3==455) v_455+=1; //4551 si 4552
      if (v3==701) v_701+=1; //7011 si 7012 si 7013
      if (v3==132) v_132+=1; //1321 si 1322
      //                  

      if (v3==534 || v3==536 || v3==537 || v3==538 || v3==539 || 
          v3==551 || v3==552 || v3==553)  sir=v3;

      //------------
             v2.push(sir);

    }//for  
 //compara
  for (var i=0; i<v2.length; i++){
    compare_a = v2[i];
    for (var j=0; j<=i; j++){
      compare_b = v2[j];
      if ( (j!=i) && (compare_a==compare_b) && (compare_a.indexOf("null")==-1) )
      {
        if (errMess1=="") errMess1 += "Ati incarcat acelasi 'Nr.de evidenta a platii' sau ati incarcat de mai multe ori aceeasi obligatie, la pozitiile: " + "\r\n\t";
        errMess1 += " - " + (i+1) + " / " + (j+1) + "\r\n\t";
      }
    }//for j
  }//for i

 if (v_754>1)  errMess1 += "Ati incarcat atat oblig.7541, cat si 7542, ceea ce nu e permis !" + "\r\n\t";
 if (v_717>1)  errMess1 += "Ati incarcat atat oblig.7171, cat si 7172, ceea ce nu e permis !" + "\r\n\t"; 

 if (v_455>1)  errMess1 += "Ati incarcat atat oblig.4551, cat si 4552, ceea ce nu e permis !" + "\r\n\t"; 
 if (v_701>1)  errMess1 += "Ati incarcat atat oblig.7011, cat si 7012 sau 7013, ceea ce nu e permis !" + "\r\n\t"; 
 if (v_132>1)  errMess1 += "Ati incarcat atat oblig.1321, cat si 1322, ceea ce nu e permis !" + "\r\n\t";  

v2 = new Array();

 return  errMess1;  

}//unicit_oblig()




function unicit_UAT(){
//cu return mesaj de eroare 
//in validari
//unicitate: cif1

  var v2 = new Array();
  var v4 = new Array();  
  var errMess1 = "";

  var sir = "";
  var sir1 = ""; 

  var compare_a;
  var compare_b;
  var v3;


//---------umple v2----------  
var n1 = form1.Judet1.all.length;
var b2;
var suma = 0;

for(var i = 0;i<n1;i++)
{
   var n2=form1.Judet1.all.item(i).UAT1.all.length;
   for(var j = 0;j<n2;j++)
   {
        b2=form1.Judet1.all.item(i).UAT1.all.item(j);
        sir=b2.cif1.rawValue;
        sir1="(judet:" + (i+1) + ", UAT:" + (j+1) + ") ";        
        v2.push(sir);
        v4.push(sir1);        
   }
}  
//---------------------  

 //compara
  for (var i=0; i<v2.length; i++){
    compare_a = v2[i];
    for (var j=0; j<=i; j++){
      compare_b = v2[j];
      if ( (j!=i) && (compare_a==compare_b) && (compare_a.indexOf("null")==-1) )
      {
        if (errMess1=="") errMess1 += "Ati incarcat acelasi 'CIF UAT'=" + compare_a + " la pozitiile: " + "\r\n\t";
        errMess1 += " - " +  v4[i] + " / " + v4[j] + "\r\n\t";
      }
    }//for j
  }//for i


v2 = new Array();

 return  errMess1;  

}//unicit_UAT()




function unicit_UAT1(judet){
//cu return mesaj de eroare 
//exit/ cif1 UAT
//unicitate pe judet : cif1

  var v2 = new Array();
  var v4 = new Array();  
  var errMess1 = "";

  var sir = "";
  var sir1 = ""; 

  var compare_a;
  var compare_b;
  var v3;


//---------umple v2----------  
var b2;
var suma = 0;

   var n2=judet.UAT1.all.length;
   for(var j = 0;j<n2;j++)
   {
      b2=judet.UAT1.all.item(j);
      if (b2.cif1.rawValue!=null)
      {
        sir=b2.cif1.rawValue;
        sir1="UAT" + (j+1) + " ";        
        v2.push(sir);
        v4.push(sir1);
      }        
   }

//---------------------  

 //compara
  for (var i=0; i<v2.length; i++){
    compare_a = v2[i];
    for (var j=0; j<=i; j++){
      compare_b = v2[j];
      if ( (j!=i) && (compare_a==compare_b) && (compare_a.indexOf("null")==-1) )
      {
        if (errMess1=="") errMess1 += "Ati incarcat acelasi 'CIF UAT'=" + compare_a + " la : " + "\r\n\t";
        errMess1 += " - " +  v4[i] + " / " + v4[j] + "\r\n\t";
      }
    }//for j
  }//for i


v2 = new Array();

 return  errMess1;  

}//unicit_UAT1()

function validateAP_CIF(pVATField){
//---------------
var sp1 = pVATField.rawValue;
if (sp1==null)	return valid;

var n1=sp1.length;
for (i=0;i<n1;i++){
  sp1=sp1.replace(" ","");
  }

pVATField.rawValue=sp1;
pAP_CIF=pVATField.rawValue;
//----------------

	var valid = true;
	if (pAP_CIF == null)
		valid = false;
	valid =  valid && !isNaN(pAP_CIF) && verifCifValid.testLength(pAP_CIF, 13);
	if (valid && pAP_CIF != null && pAP_CIF.length < 13){
		//este CUI
		var checkLength = 10 - pAP_CIF.length;
		var zeroPaddedCode  = pAP_CIF;
      	while (checkLength > 0){
        	zeroPaddedCode = "0" + zeroPaddedCode ;
        	checkLength --;
      	}
		valid = verifCifValid.validateVAT(zeroPaddedCode);
	}
	else if (valid && pAP_CIF != null && pAP_CIF.length == 13){
		valid = verifCifValid.validateCNP(pAP_CIF);
	}
	else{
		valid = false
	}

	return valid;
}


function testLength(pStr,pLength){
	return pStr == null?true:pStr.length <= pLength;
}



function validateVAT(pFiscalCode){

  var code = pFiscalCode;
  var res = 0;
  var CODE_LENGTH = 10;
  var result = false;

    res += (code.charAt(0) != 0 ) ? (7 * code.charAt(0)) : 0;
    res += (code.charAt(1) != 0 ) ? (5 * code.charAt(1)) : 0;
    res += (code.charAt(2) != 0 ) ? (3 * code.charAt(2)) : 0;
    res += (code.charAt(3) != 0 ) ? (2 * code.charAt(3)) : 0;
    res += (code.charAt(4) != 0 ) ? (1 * code.charAt(4)) : 0;
    res += (code.charAt(5) != 0 ) ? (7 * code.charAt(5)) : 0;
    res += (code.charAt(6) != 0 ) ? (5 * code.charAt(6)) : 0;
    res += (code.charAt(7) != 0 ) ? (3 * code.charAt(7)) : 0;
    res += (code.charAt(8) != 0 ) ? (2 * code.charAt(8)) : 0;

  res = (res * 10) % 11;
  if (res == 10) res = 0;

  result = (code.charAt(9) == res) ? true : false;

  return result;

}


function validateCNP(s){
	var suma = 0;
	if(s.length == 13){
		suma =	parseInt(s.charAt(0))*2 + 
				parseInt(s.charAt(1))*7 +
				parseInt(s.charAt(2))*9 +
				parseInt(s.charAt(3))*1 +
				parseInt(s.charAt(4))*4 +
				parseInt(s.charAt(5))*6 +
				parseInt(s.charAt(6))*3 + 
				parseInt(s.charAt(7))*5 + 
				parseInt(s.charAt(8))*8 +
				parseInt(s.charAt(9))*2 +
				parseInt(s.charAt(10))*7 +
				parseInt(s.charAt(11))*9;
		suma = suma%11;
		if(suma == 10)
			suma = 1;
		return suma == parseInt(s.charAt(12));
	}
	return false;
}

