var schimba;
function schDiacr(sir) {
    if(!schimba) {
        schimba = mapareDiacritice;
    }
    for(var i=0; i<schimba.length; i++) {
        sir = sir.replace(schimba[i].diacritic, schimba[i].substitut);
    }
    //---scoate spatii din stanga-----------

var sp;
var lung = sir.length;

sp = sir.substr(0, 1);
while (sp ==" ")
{
    sir = sir.substr(1, lung-1);
    lung = sir.length;
    sp = sir.substr(0, 1);
}
        return sir;
}// eof schDiacr



function schEnt(Ref)
{
var sir = "";
sir = Ref.replace(/[&]/g,"&amp;"); 
sir = sir.replace(/[<]/g,"&lt;");
sir = sir.replace(/[>]/g,"&gt;"); 
sir = sir.replace(/["]/g,"&quot;"); 
sir = sir.replace(/[']/g,"&apos;");
return sir; 
}// eof schEnt

// indeparteaza spatii din ambele parti ale unui sir
function trimSpaces(x) {
    return x.replace(/^\s+|\s+$/gm,'');
}
// indepartare spatii din sir
function remSpaces(x) {
    return x.replace(/\s+/g, '');
}

