function RNDn(nr, n)
{
	var res = Math.round(nr*Math.pow(10,n))/Math.pow(10,n);
	return res;
}

function isDate(val,format)
{
	var date = util.scand(format, val);
	if (date == null) return false; 
	else return true;
}

function pune_zile_an(startDate){

if (startDate!=null)
{//ani bisecti 2012 2016 2020 2024 cu 29zile 
   var nr_zile=364;
   var v1 = Functii.EL(Functii.DT(startDate.toString()));  //obtinem zz.ll.aaaa
   var lu1=v1.substr(3,2);
   var an1=v1.substr(6,4);
   //ex: [03.2011 - 02.2012] --> 1+365zile
   if ((an1==2011 || an1==2015 || an1==2019 || an1==2023 || an1==2027 || an1==2031) && (lu1>2)) nr_zile=365;
   if ((an1==2012 || an1==2016 || an1==2020 || an1==2024 || an1==2028 || an1==2032) && (lu1<3)) nr_zile=365; 
   //nu merge pt.01.04.2012 formeaza 30.03.2013 (364) sau 01.04.2013 (365) ????
   //app.alert(an1+"."+lu1+"-"+nr_zile); 
} 

return nr_zile;
}//pune_zile_an(startDate)




